#!/usr/bin/env node

const fs = require("fs-extra");
const path = require("path");

const projectName = process.argv[2];

if (!projectName) {
  console.log("Informe o nome do projeto:");
  console.log("npx backend-aula nome-do-projeto");
  process.exit(1);
}

const projectPath = path.join(process.cwd(), projectName);

// Criar pasta
fs.ensureDirSync(projectPath);
fs.ensureDirSync(path.join(projectPath, "src"));

// Criar package.json do projeto gerado
fs.writeJsonSync(
  path.join(projectPath, "package.json"),
  {
    name: projectName,
    version: "1.0.0",
    main: "src/server.js",
    scripts: {
      dev: "nodemon src/server.js",
    },
  },
  { spaces: 2 },
);

// Criar .env
fs.writeFileSync(path.join(projectPath, ".env"), `PORT=3000`);

// Criar server.js
fs.writeFileSync(
  path.join(projectPath, "src/server.js"),
  `const express = require('express');
require('dotenv').config();

const app = express();
app.use(express.json());

app.get('/', (req, res) => {
  res.json({ mensagem: "API funcionando" });
});

const PORT = process.env.PORT || 3000;

app.listen(PORT, () => {
  console.log(\`Servidor rodando na porta \${PORT}\`);
});
`,
);

console.log("Projeto criado com sucesso!");
console.log("Agora execute:");
console.log("cd " + projectName);
console.log("npm install express dotenv nodemon");
console.log("npm run dev");
